import time
import requests
from web3 import Web3

# 1. Connect to the Live Sepolia Network
infura_url = "https://sepolia.drpc.org"
web3 = Web3(Web3.HTTPProvider(infura_url))

# 2. Your Credentials
wallet_address = "0xa07275Dc71cB26Ecc6CD701d56410A63956D1E25"
private_key = "YOUR PRIVATE KEY"  

# 3. Contract Parts
abi = [{"inputs": [{"internalType": "address", "name": "_receiver", "type": "address"}, {"internalType": "string", "name": "_cargoName", "type": "string"}, {"internalType": "int256", "name": "_maxTemperature", "type": "int256"}], "stateMutability": "nonpayable", "type": "constructor"}, {"inputs": [{"internalType": "int256", "name": "_newTemp", "type": "int256"}], "name": "updateTemperature", "outputs": [], "stateMutability": "nonpayable", "type": "function"}, {"inputs": [], "name": "cargoName", "outputs": [{"internalType": "string", "name": "", "type": "string"}], "stateMutability": "view", "type": "function"}, {"inputs": [], "name": "currentTemperature", "outputs": [{"internalType": "int256", "name": "", "type": "int256"}], "stateMutability": "view", "type": "function"}, {"inputs": [], "name": "maxTemperature", "outputs": [{"internalType": "int256", "name": "", "type": "int256"}], "stateMutability": "view", "type": "function"}, {"inputs": [], "name": "receiver", "outputs": [{"internalType": "address", "name": "", "type": "address"}], "stateMutability": "view", "type": "function"}, {"inputs": [], "name": "sender", "outputs": [{"internalType": "address", "name": "", "type": "address"}], "stateMutability": "view", "type": "function"}, {"inputs": [], "name": "shipmentStatus", "outputs": [{"internalType": "string", "name": "", "type": "string"}], "stateMutability": "view", "type": "function"}]
bytecode = ""

# ---------------------------------------------------------
# 4. Talk to the n8n Control Tower (GET DATA)
# -> This hits "Webhook2" to read the Google Sheet
# ---------------------------------------------------------
n8n_get_url = "https://n8n.vedsan8n52002.xyz/webhook/get-pending"

print("🔄 Checking AKies Global Database for pending orders...")
try:
    response = requests.get(n8n_get_url)
    orders = response.json()
except Exception as e:
    print(f"❌ Failed to reach n8n: {e}")
    exit()

# If the list is empty or doesn't exist, we stop
if not orders or len(orders) == 0:
    print("✅ No pending orders found. Factory floor is standing by.")
    exit()

# 5. Extract the first pending order
order = orders[0]
row_number = order.get("row_number")
cargo_name = order.get("Cargo Name")
max_temp = int(order.get("Max Temp"))
receiver = order.get("Receiver Address")

print(f"\n📥 NEW ORDER RECEIVED (Row {row_number}): {cargo_name} | Max Temp: {max_temp}°C")
print("🛠️ Forging smart contract on the blockchain...")

# 6. Build and Deploy
TransitLogger = web3.eth.contract(abi=abi, bytecode=bytecode)
nonce = web3.eth.get_transaction_count(wallet_address, 'pending')

transaction = TransitLogger.constructor(receiver, cargo_name, max_temp).build_transaction({
    'chainId': 11155111,
    'gas': 3000000,
    'maxFeePerGas': web3.to_wei('10', 'gwei'),
    'maxPriorityFeePerGas': web3.to_wei('2', 'gwei'),
    'nonce': nonce,
})

signed_txn = web3.eth.account.sign_transaction(transaction, private_key=private_key)
tx_hash = web3.eth.send_raw_transaction(signed_txn.raw_transaction)

print(f"🚀 Transaction sent! Hash: {web3.to_hex(tx_hash)}")
print("⏳ Waiting for global network confirmation...")

receipt = web3.eth.wait_for_transaction_receipt(tx_hash)
new_contract_address = receipt.contractAddress

print(f"\n✅ SUCCESS! Contract deployed at: {new_contract_address}")
print("-" * 50)


# ---------------------------------------------------------
# 7. Update the AKies Global Database (POST DATA)
# -> This hits "Update Valve" to write to the Google Sheet
# ---------------------------------------------------------
print("🔄 Sending contract address back to the control tower...")
update_url = "https://n8n.vedsan8n52002.xyz/webhook/update-status"

payload = {
    "row_number": row_number,
    "contract_address": new_contract_address
}

try:
    requests.post(update_url, json=payload)
    print("✅ Database updated! Order marked as DEPLOYED.")
except Exception as e:
    print(f"⚠️ Failed to update database: {e}")
    
print("🏁 FULL AUTOMATION CYCLE COMPLETE.")
